import React, { useState } from 'react';
import { Save, X } from 'lucide-react';

const DynamicTaskForm = ({ taskDefinitionKey, taskName, onSubmit, onCancel, loading }) => {
  const [formData, setFormData] = useState({});

  // Form configurations based on task definition keys
  const formConfigs = {
    // Complaint Registration Form
    'FormTask_67': {
      title: 'Complaint Registration',
      fields: [
        {
          name: 'customerName',
          label: 'Customer Name',
          type: 'text',
          required: true,
          placeholder: 'Enter customer name'
        },
        {
          name: 'email',
          label: 'Email Address',
          type: 'email',
          required: true,
          placeholder: 'customer@example.com'
        },
        {
          name: 'phone',
          label: 'Phone Number',
          type: 'tel',
          required: true,
          placeholder: '+2519XXXXXXXX'
        },
        {
          name: 'accountNumber',
          label: 'Account Number',
          type: 'text',
          required: true,
          placeholder: 'Enter account number'
        },
        {
          name: 'complaintChannel',
          label: 'Complaint Channel',
          type: 'select',
          required: true,
          options: [
            { value: 'email', label: 'Email' },
            { value: 'phone', label: 'Phone' },
            { value: 'branch', label: 'Branch' },
            { value: 'website', label: 'Website' },
            { value: 'social', label: 'Social Media' }
          ]
        },
        {
          name: 'complaintDescription',
          label: 'Complaint Description',
          type: 'textarea',
          required: true,
          placeholder: 'Describe the complaint in detail...',
          rows: 4
        }
      ]
    },

    // CMD Screening & Classification Form
    'FormTask_43': {
      title: 'Screening & Classification',
      fields: [
        {
          name: 'complaintCategory',
          label: 'Complaint Category',
          type: 'select',
          required: true,
          options: [
            { value: 'HS', label: 'HS - Service Quality' },
            { value: 'S', label: 'S - Audit Required' },
            { value: 'G', label: 'G - General' }
          ]
        },
        {
          name: 'priorityLevel',
          label: 'Priority Level',
          type: 'select',
          required: true,
          options: [
            { value: 'P1', label: 'P1 - High Priority' },
            { value: 'P2', label: 'P2 - Medium Priority' },
            { value: 'P3', label: 'P3 - Low Priority' }
          ]
        },
        {
          name: 'requiresInvestigation',
          label: 'Requires Investigation',
          type: 'checkbox',
          description: 'Check if this complaint requires detailed investigation'
        },
        {
          name: 'assignedDepartment',
          label: 'Assigned Department',
          type: 'select',
          required: true,
          options: [
            { value: 'service-quality', label: 'Service Quality' },
            { value: 'audit-team', label: 'Audit Team' },
            { value: 'work-unit', label: 'Work Unit' },
            { value: 'marketing', label: 'Marketing' }
          ]
        },
        {
          name: 'notes',
          label: 'Additional Notes',
          type: 'textarea',
          placeholder: 'Add any additional notes or comments...',
          rows: 3
        }
      ]
    },

    // First Contact Resolution Form
    'FormTask_8': {
      title: 'First Contact Resolution',
      fields: [
        {
          name: 'isFCR',
          label: 'First Contact Resolution',
          type: 'radio',
          required: true,
          options: [
            { value: true, label: 'Yes - Resolved in first contact' },
            { value: false, label: 'No - Requires escalation' }
          ]
        },
        {
          name: 'fcrComments',
          label: 'FCR Comments',
          type: 'textarea',
          required: true,
          placeholder: 'Describe the resolution provided...',
          rows: 4
        }
      ]
    },

    // Investigation Form (Audit Team)
    'FormTask_48': {
      title: 'Investigation Form',
      fields: [
        {
          name: 'investigationFindings',
          label: 'Investigation Findings',
          type: 'textarea',
          required: true,
          placeholder: 'Detail your investigation findings...',
          rows: 5
        },
        {
          name: 'investigationResult',
          label: 'Investigation Result',
          type: 'select',
          required: true,
          options: [
            { value: 'approved', label: 'Approved - Complaint valid' },
            { value: 'rejected', label: 'Rejected - Complaint invalid' },
            { value: 'partial', label: 'Partial - Partially valid' }
          ]
        },
        {
          name: 'investigationComments',
          label: 'Investigation Comments',
          type: 'textarea',
          placeholder: 'Additional comments about the investigation...',
          rows: 3
        }
      ]
    },

    // Resolution Form (Department / Service Quality)
    'FormTask_57': {
      title: 'Resolution Form',
      fields: [
        {
          name: 'resolutionDetails',
          label: 'Resolution Details',
          type: 'textarea',
          required: true,
          placeholder: 'Describe the resolution in detail...',
          rows: 4
        },
        {
          name: 'actionTaken',
          label: 'Action Taken',
          type: 'textarea',
          required: true,
          placeholder: 'What actions were taken to resolve this complaint?',
          rows: 3
        },
        {
          name: 'isSensitive',
          label: 'Sensitive Case',
          type: 'checkbox',
          description: 'Mark if this is a sensitive case requiring special handling'
        },
        {
          name: 'resolutionStatus',
          label: 'Resolution Status',
          type: 'select',
          required: true,
          options: [
            { value: 'resolved', label: 'Resolved' },
            { value: 'partially-resolved', label: 'Partially Resolved' },
            { value: 'escalated', label: 'Escalated' },
            { value: 'closed', label: 'Closed' }
          ]
        }
      ]
    },

    // Feedback Form
    'FormTask_72': {
      title: 'Customer Feedback',
      fields: [
        {
          name: 'satisfactionRating',
          label: 'Satisfaction Rating',
          type: 'select',
          required: true,
          options: [
            { value: '5', label: '5 - Very Satisfied' },
            { value: '4', label: '4 - Satisfied' },
            { value: '3', label: '3 - Neutral' },
            { value: '2', label: '2 - Dissatisfied' },
            { value: '1', label: '1 - Very Dissatisfied' }
          ]
        },
        {
          name: 'feedbackComments',
          label: 'Feedback Comments',
          type: 'textarea',
          placeholder: 'Please provide your feedback...',
          rows: 4
        }
      ]
    }
  };

  // Get form configuration for current task
  const formConfig = formConfigs[taskDefinitionKey] || {
    title: 'Task Completion',
    fields: [
      {
        name: 'comments',
        label: 'Comments',
        type: 'textarea',
        placeholder: 'Add any comments...',
        rows: 3
      }
    ]
  };

  const handleInputChange = (name, value) => {
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    onSubmit(formData);
  };

  const renderField = (field) => {
    const { name, label, type, required, placeholder, options, rows, description } = field;
    const value = formData[name] || (type === 'checkbox' ? false : '');

    switch (type) {
      case 'text':
      case 'email':
      case 'tel':
        return (
          <input
            type={type}
            id={name}
            value={value}
            onChange={(e) => handleInputChange(name, e.target.value)}
            required={required}
            placeholder={placeholder}
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
          />
        );

      case 'textarea':
        return (
          <textarea
            id={name}
            value={value}
            onChange={(e) => handleInputChange(name, e.target.value)}
            required={required}
            placeholder={placeholder}
            rows={rows || 3}
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
          />
        );

      case 'select':
        return (
          <select
            id={name}
            value={value}
            onChange={(e) => handleInputChange(name, e.target.value)}
            required={required}
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
          >
            <option value="">Select an option...</option>
            {options?.map(option => (
              <option key={option.value} value={option.value}>
                {option.label}
              </option>
            ))}
          </select>
        );

      case 'checkbox':
        return (
          <div className="flex items-center">
            <input
              type="checkbox"
              id={name}
              checked={value}
              onChange={(e) => handleInputChange(name, e.target.checked)}
              className="h-4 w-4 text-primary-600 focus:ring-primary-500 border-gray-300 rounded"
            />
            <label htmlFor={name} className="ml-2 text-sm text-gray-700">
              {description || label}
            </label>
          </div>
        );

      case 'radio':
        return (
          <div className="space-y-2">
            {options?.map(option => (
              <div key={option.value} className="flex items-center">
                <input
                  type="radio"
                  id={`${name}_${option.value}`}
                  name={name}
                  value={option.value}
                  checked={value === option.value}
                  onChange={(e) => handleInputChange(name, e.target.value)}
                  required={required}
                  className="h-4 w-4 text-primary-600 focus:ring-primary-500 border-gray-300"
                />
                <label htmlFor={`${name}_${option.value}`} className="ml-2 text-sm text-gray-700">
                  {option.label}
                </label>
              </div>
            ))}
          </div>
        );

      default:
        return (
          <input
            type="text"
            id={name}
            value={value}
            onChange={(e) => handleInputChange(name, e.target.value)}
            required={required}
            placeholder={placeholder}
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
          />
        );
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-medium text-gray-900">{formConfig.title}</h3>
        <button
          type="button"
          onClick={onCancel}
          className="text-gray-400 hover:text-gray-600"
        >
          <X className="w-5 h-5" />
        </button>
      </div>

      <div className="grid grid-cols-1 gap-6">
        {formConfig.fields.map((field) => (
          <div key={field.name}>
            {field.type !== 'checkbox' && (
              <label htmlFor={field.name} className="block text-sm font-medium text-gray-700 mb-2">
                {field.label}
                {field.required && <span className="text-red-500 ml-1">*</span>}
              </label>
            )}
            {renderField(field)}
            {field.description && field.type !== 'checkbox' && (
              <p className="mt-1 text-sm text-gray-500">{field.description}</p>
            )}
          </div>
        ))}
      </div>

      <div className="flex justify-end space-x-3 pt-6 border-t border-gray-200">
        <button
          type="button"
          onClick={onCancel}
          className="px-4 py-2 text-gray-700 bg-gray-100 rounded-lg hover:bg-gray-200 transition-colors"
        >
          Cancel
        </button>
        <button
          type="submit"
          disabled={loading}
          className="flex items-center space-x-2 px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 transition-colors disabled:opacity-50"
        >
          {loading ? (
            <>
              <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white"></div>
              <span>Processing...</span>
            </>
          ) : (
            <>
              <Save className="w-4 h-4" />
              <span>Complete Task</span>
            </>
          )}
        </button>
      </div>
    </form>
  );
};

export default DynamicTaskForm;
